python3 << 'EOF'
import numpy as np, pickle
d = pickle.load(open('dense.pkl','rb'))
D, S, keys = d['D'], d['S'], d['keys']
nk = D.shape[0]
pres = (D[:, 1:366] > 0).mean(1)
hi = np.where(pres >= 0.60)[0]
print('high-presence keys:', len(hi), 'mean q:', pres[hi].mean().round(3))
Dx = np.zeros((nk, 386), dtype=np.int8); Dx[:, :366] = D
Sx = np.zeros((nk, 386), dtype=np.int8); Sx[:, :366] = S
# A: purchase + silent days1-5 ; B: same silence with stockout at t (null-ish control)
winsA = []; winsB = []
for k in hi:
    for t in range(1, 352):
        if (Dx[k, t+1:t+6] == 0).all():
            if Sx[k, t] > 0: winsA.append((k, t))
            elif Dx[k, t] > 0: winsB.append((k, t))
print('A windows (buy + 5-day silence):', len(winsA), ' B windows (stockout + 5-day silence):', len(winsB))
def profile(wins):
    out = []
    for off in range(6, 22):
        vals = np.array([Dx[k, t+off] for k, t in wins if t+off <= 365])
        out.append((off, round((vals > 0).mean(), 3), round(vals[vals > 0].mean() if (vals > 0).any() else 0, 2),
                    dict(zip(*[x.tolist() for x in np.unique(vals[vals>0], return_counts=True)]))))
    return out
print('A: off | presence | mean qty | qty counts')
for r in profile(winsA): print(r)
print('B: off | presence | mean qty')
for r in profile(winsB): print(r)
